query:
UPDATE customers 
SET monthlyCost = (
  SELECT COALESCE(SUM(monthlyCost), 0) 
  FROM services 
  WHERE customerExternalId = 'C0087' AND (status IS NULL OR status != 'terminated')
)
WHERE externalId = 'C0087';

SELECT externalId, name, monthlyCost FROM customers WHERE externalId = 'C0087';

